```json
{
  "patch": {
    "firstValueMoment": "The user opens their inbox and sees the completed, signed agreement, proving the system worked and their document is legally binding without printing or scanning.",
    "frictionScore": 85,
    "experiments": [
      {
        "hypothesis": "Offer a pre-signed demo envelope on the Getting Started screen that the user can open immediately to see what a completed agreement looks like in their inbox.",
        "rationale": "The user waits for a counterparty to sign before they see value. A demo envelope delivers the first value moment in seconds, with no dependency on another party. This gets more users to the felt outcome (a signed document in the inbox) before the trial clock matters, and proves the product works before they invest in sending a real envelope.",
        "lever": "value-moment"
      },
      {
        "hypothesis": "Let the user save a template from their first envelope and prompt them to send it to another counterparty within the trial window.",
        "rationale": "The user sends one envelope and does not return until they need another document signed, which may be weeks or months later. A saved template with a prompt to send it again creates a second signing event inside the trial, proving the product's repeat value when the user's workflow actually recurs. This builds recurrence by showing the user that the tool handles multiple agreements, not just one.",
        "lever": "durable-value"
      },
      {
        "hypothesis": "Let the user upload a document and tag fields before creating an account, then gate the send behind signup.",
        "rationale": "The user clears seven steps (email, personal info, two verification codes, phone again, password, payment) before they can upload a document. Moving the upload and field-tagging to the front of the flow gets the user closer to value before they hit the signup wall, and gives them a concrete artifact (a prepared envelope) that they want to send. This speeds arrival-to-first-value by letting the user start work immediately, then converting them when they are ready to send.",
        "lever": "value-moment"
      }
    ]
  },
  "changes": [
    {
      "target": "first-value-moment",
      "before": "A counterparty opens the envelope, signs the document, and the completed agreement lands back in the sender's inbox.",
      "after": "The user opens their inbox and sees the completed, signed agreement, proving the system worked and their document is legally binding without printing or scanning.",
      "reason": "The critic is right. The original statement conflates the dependency (counterparty signs) with the felt outcome (user sees proof in their inbox). Value arrives when the user experiences the completed document, not when the signer acts. The corrected version names the moment the user opens their inbox and sees the signed agreement, which is the felt-value moment the user came for."
    },
    {
      "target": "friction-score",
      "before": "78",
      "after": "85",
      "reason": "The critic is right. The flow combines a seven-step gate stack (email verification, phone verification twice, password, payment info) with a dependency on a counterparty who may not act quickly. A score of 78 sits at the low end of the 67-100 band when the friction is clearly high within that range. Raising the score to 85 reflects the combination of required steps and uncontrolled wait time."
    },
    {
      "target": "ranking",
      "before": "Experiment 2 (reminder to check status) ranked second",
      "after": "Experiment 2 (save template, prompt second send) ranked second",
      "reason": "The critic is right. The original experiment 2 was a funnel-only lever disguised as durable-value. A reminder to check status does not deliver value and does not build recurrence, it only brings the user back to confirm that they are still waiting. Experiment 1 already delivers the first value moment faster, so the second experiment must build real recurrence. The new experiment 2 prompts the user to send a second envelope from a saved template, creating a repeat signing event within the trial that proves the product's recurring value."
    },
    {
      "target": "experiment",
      "before": "Add a 'Send a reminder in 3 days' option on the envelope confirmation screen, positioned as a habit-building feature rather than a nudge.",
      "after": "Let the user save a template from their first envelope and prompt them to send it to another counterparty within the trial window.",
      "reason": "The critic is right. The original experiment 2 claimed to build a habit around follow-up, but follow-up on a pending envelope is not a use case when the user is just checking if the signer has acted yet. That is a funnel-only lever. The corrected experiment creates a second signing event by letting the user save a template and send it again, which builds real recurrence by proving the product handles multiple agreements."
    }
  ]
}
